const params = $input.first().json.params;
const shipmentId = parseInt(params.id);

if (!shipmentId || isNaN(shipmentId)) {
  throw new Error('Invalid shipment ID');
}

return { shipmentId };

const shipment = $('Get Shipment').first().json;
const logs = $input.all().map(item => item.json);

if (!shipment || !shipment.id) {
  return {
    success: false,
    error: 'Shipment not found'
  };
}

// 格式化 shipment 数据
const formattedShipment = {
  id: shipment.id,
  tokenCode: shipment.token_code,
  fromAddress: shipment.from_address,
  toAddress: shipment.to_address,
  weight: parseFloat(shipment.weight),
  parcelDetails: shipment.parcel_details,
  status: shipment.status,
  quoteAmount: shipment.quote_amount ? parseFloat(shipment.quote_amount) : null,
  trackingNumber: shipment.tracking_number,
  trackingStatus: shipment.tracking_status,
  trackingUrl: shipment.tracking_url,
  labelUrl: shipment.label_url,
  carrier: shipment.carrier,
  serviceName: shipment.service_name,
  estimatedDays: shipment.estimated_days,
  shippoObjectId: shipment.shippo_object_id,
  shippoRateId: shipment.shippo_rate_id,
  shippoRates: shipment.shippo_rates,
  stripePaymentId: shipment.stripe_payment_id,
  paidAt: shipment.paid_at,
  createdAt: shipment.created_at,
  updatedAt: shipment.updated_at
};

// 格式化 logs
const formattedLogs = logs.map(log => ({
  actionType: log.action_type,
  details: log.details,
  success: log.success,
  errorMsg: log.error_msg,
  createdAt: log.created_at
}));

return {
  success: true,
  shipment: formattedShipment,
  logs: formattedLogs
};
